insert into "users" ("id", "email", "name", "phone", "avatar", "address", "password_hash", "role_id", "created_at", "updated_at") values ('11111111-1111-4111-8111-111111111111', 'alice.admin@example.com', 'Alice Admin', '0901000111', null, null, 'pbkdf2-sha256$120000$MkWKt8X/yn4T6k045cUm2Q==$Uwa/OtrEVy4zYHcH/ShbRBu7CfipLQn0ZV6uUyxQUso=', '00000000-0000-4000-8000-000000000002', '2026-04-17T04:49:30.147Z', '2026-04-17T04:49:30.147Z'), ('22222222-2222-4222-8222-222222222222', 'bob.user@example.com', 'Bob User', '0902000222', null, null, 'pbkdf2-sha256$120000$QdOlh0ctlN+Iso0GAieTow==$fLluYQATjsrf/wANbAm5ZS0CAs3vYQLJx0bmBKYR848=', '00000000-0000-4000-8000-000000000001', '2026-04-17T04:49:30.147Z', '2026-04-17T04:49:30.147Z');
insert into "posts" ("id", "user_id", "title", "content", "excerpt", "cover_image", "category", "slug", "is_published", "created_at", "updated_at") values ('33333333-3333-4333-8333-333333333333', '11111111-1111-4111-8111-111111111111', 'Kinh nghiệm thuê nhà nguyên căn giá rẻ tại Hà Nội', '<p>Việc tìm thuê một căn nhà nguyên căn giá rẻ nhưng vẫn đảm bảo chất lượng sống tại Hà Nội luôn là bài toán khó với nhiều người.</p><h3>1. Xác định rõ nhu cầu và ngân sách</h3><p>Hãy xác định ngân sách và khu vực trước khi đi xem nhà.</p>', 'Những lưu ý quan trọng khi tìm thuê nhà nguyên căn để tránh bị lừa đảo và tìm được căn nhà ưng ý.', 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&q=80&w=1200', 'Kinh nghiệm thuê', 'kinh-nghiem-thue-nha-ha-noi', 1, '2026-04-17T04:49:30.147Z', '2026-04-17T04:49:30.147Z'), ('44444444-4444-4444-8444-444444444444', '22222222-2222-4222-8222-222222222222', 'Cách bố trí phòng trọ hợp phong thủy thu hút tài lộc', '<p>Hướng dẫn cách sắp xếp đồ đạc trong phòng trọ nhỏ sao cho hợp phong thủy, mang lại may mắn.</p>', 'Hướng dẫn cách sắp xếp đồ đạc trong phòng trọ nhỏ sao cho hợp phong thủy, mang lại may mắn.', 'https://images.unsplash.com/photo-1513694203232-719a280e022f?auto=format&fit=crop&q=80&w=1200', 'Phong thủy', 'phong-thuy-phong-tro', 1, '2026-04-17T04:49:30.147Z', '2026-04-17T04:49:30.147Z'), ('55555555-5555-4555-8555-555555555555', '11111111-1111-4111-8111-111111111111', 'Hợp đồng thuê nhà: Những điều khoản cần đặc biệt chú ý', '<p>Phân tích chi tiết các điều khoản trong hợp đồng thuê nhà để bảo vệ quyền lợi của người đi thuê.</p>', 'Phân tích chi tiết các điều khoản trong hợp đồng thuê nhà để bảo vệ quyền lợi của người đi thuê.', 'https://images.unsplash.com/photo-1450101499163-c8848c66ca85?auto=format&fit=crop&q=80&w=1200', 'Pháp lý', 'hop-dong-thue-nha', 1, '2026-04-17T04:49:30.147Z', '2026-04-17T04:49:30.147Z'), ('bd222222-2222-4222-a222-222222222201', '22222222-2222-4222-8222-222222222222', 'Thị trường cho thuê căn hộ chung cư tăng nhiệt', '<p>Cập nhật tình hình thị trường cho thuê căn hộ chung cư tại các thành phố lớn trong quý 2/2024.</p>', 'Cập nhật tình hình thị trường cho thuê căn hộ chung cư tại các thành phố lớn trong quý 2/2024.', 'https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?auto=format&fit=crop&q=80&w=1200', 'Tin tức', 'thi-truong-can-ho-2024', 1, '2026-04-17T04:49:30.147Z', '2026-04-17T04:49:30.147Z'), ('bd222222-2222-4222-a222-222222222202', '11111111-1111-4111-8111-111111111111', 'Mẹo trang trí phòng trọ siêu đẹp với chi phí thấp', '<p>Gợi ý các món đồ decor giá rẻ giúp biến hóa căn phòng trọ nhàm chán trở nên lung linh.</p>', 'Gợi ý các món đồ decor giá rẻ giúp biến hóa căn phòng trọ nhàm chán trở nên lung linh.', 'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?auto=format&fit=crop&q=80&w=1200', 'Kinh nghiệm thuê', 'meo-trang-tri-phong-tro', 1, '2026-04-17T04:49:30.147Z', '2026-04-17T04:49:30.147Z'), ('bd222222-2222-4222-a222-222222222203', '22222222-2222-4222-8222-222222222222', 'Quy định mới về đăng ký tạm trú cho người thuê nhà', '<p>Cập nhật những thay đổi mới nhất về thủ tục đăng ký tạm trú mà người đi thuê cần biết.</p>', 'Cập nhật những thay đổi mới nhất về thủ tục đăng ký tạm trú mà người đi thuê cần biết.', 'https://images.unsplash.com/photo-1589829085413-56de8ae18c73?auto=format&fit=crop&q=80&w=1200', 'Pháp lý', 'dang-ky-tam-tru', 1, '2026-04-17T04:49:30.147Z', '2026-04-17T04:49:30.147Z');
insert into "comments" ("id", "user_id", "post_id", "content", "created_at") values ('66666666-6666-4666-8666-666666666666', '22222222-2222-4222-8222-222222222222', '33333333-3333-4333-8333-333333333333', 'Bài viết rất hữu ích, cảm ơn bạn đã chia sẻ!', '2026-04-17T04:49:30.147Z'), ('77777777-7777-4777-8777-777777777777', '11111111-1111-4111-8111-111111111111', '33333333-3333-4333-8333-333333333333', 'Mình đang tìm thuê ở Cầu Giấy, có tips gì thêm không?', '2026-04-17T04:49:30.147Z');
